import{_ as a,o as s,c as r,a2 as o}from"./chunks/framework.D5wUhsuj.js";const t="/docs/assets/workspace-selector.CFw-c1Yg.png",k=JSON.parse('{"title":"Workspaces","description":"","frontmatter":{},"headers":[],"relativePath":"platform/workspaces.md","filePath":"platform/workspaces.md","lastUpdated":1783546178000}'),c={name:"platform/workspaces.md"};function n(i,e,l,p,d,h){return s(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="workspaces" tabindex="-1">Workspaces <a class="header-anchor" href="#workspaces" aria-label="Permalink to &quot;Workspaces&quot;">​</a></h1><p>Workspaces are the main scope boundary in prokube. They group the workloads, storage, credentials, and access rules that belong to a user or team.</p><p>Use this page to understand what changes when you switch workspaces, what access levels mean, and which security implications matter when sharing a workspace.</p><h2 id="what-a-workspace-controls" tabindex="-1">What a Workspace Controls <a class="header-anchor" href="#what-a-workspace-controls" aria-label="Permalink to &quot;What a Workspace Controls&quot;">​</a></h2><p>The selected workspace affects which resources you can see and create across the platform:</p><ul><li>Labs and their mounted workspace storage</li><li>pipeline runs, experiments, and related Kubernetes resources</li><li>model-serving endpoints and serverless workloads</li><li>workspace-scoped secrets and registry credentials</li><li>object-storage buckets and access credentials</li><li>AgentOps resources such as sandboxes, MCP servers, and memory stores where enabled</li></ul><p>Each workspace has its own Kubernetes namespace. That namespace is one part of the workspace boundary; the workspace also includes platform-level access rules, storage configuration, UI scope, and integrations with other services.</p><h2 id="personal-and-shared-workspaces" tabindex="-1">Personal and Shared Workspaces <a class="header-anchor" href="#personal-and-shared-workspaces" aria-label="Permalink to &quot;Personal and Shared Workspaces&quot;">​</a></h2><h3 id="personal-workspaces" tabindex="-1">Personal Workspaces <a class="header-anchor" href="#personal-workspaces" aria-label="Permalink to &quot;Personal Workspaces&quot;">​</a></h3><p>Each user gets a personal workspace for their own experiments, development environments, and private platform resources.</p><p>Personal workspaces are tied to user lifecycle. Administrators manage them through user and workspace administration; attached personal workspaces are not deleted as regular project workspaces from the Workspaces page.</p><h3 id="shared-workspaces" tabindex="-1">Shared Workspaces <a class="header-anchor" href="#shared-workspaces" aria-label="Permalink to &quot;Shared Workspaces&quot;">​</a></h3><p>Shared workspaces are for teams that work together on cluster resources such as pipelines, models, agents, Labs, object-storage buckets, and workspace-scoped credentials.</p><p>Use a shared workspace when multiple users need to collaborate on the same resources.</p><p>Shared workspace access can be granted directly to users or through groups. Group-based access is preferred for teams because it keeps membership and workspace access separate: administrators grant the group access to a workspace once, then add or remove users from the group.</p><div class="warning custom-block"><p class="custom-block-title">Keep workspace boundaries intentional</p><p>Do not invite contributors into personal workspaces. Personal workspaces commonly contain user-specific Labs, storage, credentials, and temporary experiments.</p><p>Do not put personal credentials, administrator tokens, or unrelated customer data into a shared workspace. Use credentials created for that team and workload instead.</p></div><h2 id="access-levels" tabindex="-1">Access Levels <a class="header-anchor" href="#access-levels" aria-label="Permalink to &quot;Access Levels&quot;">​</a></h2><p>Workspace access determines what a user can do inside that workspace.</p><table tabindex="0"><thead><tr><th>Access level</th><th>Typical capabilities</th></tr></thead><tbody><tr><td>View</td><td>Inspect workloads, metadata, logs, and workspace resources where read access is allowed.</td></tr><tr><td>Edit</td><td>Create, update, and delete workspace workloads such as Labs, pipelines, model-serving resources, and secrets.</td></tr><tr><td>Owner</td><td>Manage the workspace and its contributors where owner-level access is enabled.</td></tr></tbody></table><p>Exact permissions can depend on platform configuration. When in doubt, check with your platform administrator before storing sensitive credentials or production data in a shared workspace.</p><h2 id="select-a-workspace" tabindex="-1">Select a Workspace <a class="header-anchor" href="#select-a-workspace" aria-label="Permalink to &quot;Select a Workspace&quot;">​</a></h2><p>Some platform views are workspace-scoped. Select the active workspace before using services that create or inspect workload resources, such as Labs, Pipelines, MCP servers, agents, model-serving endpoints, or Kubernetes resources.</p><img class="pk-docs-small-screenshot" src="'+t+'" alt="Workspace selector in the prokube UI"><p>The workspace selector controls which workspace-scoped resources are shown or created in those views.</p><p>As a rule of thumb, workspace selection matters for services that schedule workloads or create workspace-scoped Kubernetes resources.</p><p>Other services handle access through their own integration with prokube. For example, object-storage browsers, MLflow, or similar integrated tools can use OIDC-based user and workspace permissions configured by the platform backend. In those cases, the active workspace selector is not necessarily the control that determines which buckets, experiments, models, or artifacts the current user can access.</p><h2 id="manage-your-own-workspace" tabindex="-1">Manage Your Own Workspace <a class="header-anchor" href="#manage-your-own-workspace" aria-label="Permalink to &quot;Manage Your Own Workspace&quot;">​</a></h2><p>When owner self-service is enabled, workspace owners can open <strong>My Workspaces</strong> to manage members of workspaces they own. This page is not the same as administrator workspace management:</p><ul><li>owners see only workspaces they own;</li><li>owners can add members by email and remove members from their workspace;</li><li>owners do not create or delete workspaces from this page;</li><li>administrator-only settings such as security policy and egress profiles remain under <strong>User Management</strong>.</li></ul><p>Members added through owner self-service receive editor access.</p><h2 id="workspace-level-policies" tabindex="-1">Workspace-Level Policies <a class="header-anchor" href="#workspace-level-policies" aria-label="Permalink to &quot;Workspace-Level Policies&quot;">​</a></h2><p>Administrators can attach additional policy controls to a workspace:</p><ul><li><strong>Security policy</strong>: requires new and updated Labs in the workspace to use hardened security settings.</li><li><strong>Egress profile</strong>: restricts outbound network access for covered workloads to approved destinations.</li></ul><p>Egress profiles are managed under <strong>User Management</strong> &gt; <strong>Network Policies</strong>. See <a href="./../admin/network_policies.html">Network Policies</a>.</p><h2 id="security-implications" tabindex="-1">Security Implications <a class="header-anchor" href="#security-implications" aria-label="Permalink to &quot;Security Implications&quot;">​</a></h2><p>Workspace access affects more than UI pages. It can also affect Kubernetes resources, mounted storage, object-storage credentials, registry credentials, and workload configuration.</p><p>Users with sufficient workspace access may be able to read <a href="https://kubernetes.io/docs/concepts/configuration/secret/" target="_blank" rel="noreferrer">Kubernetes Secrets</a> in the workspace namespace. Store only credentials that are intended for that workspace and workload.</p><p>For production workloads, use dedicated credentials with the minimum required access.</p><h2 id="request-or-change-access" tabindex="-1">Request or Change Access <a class="header-anchor" href="#request-or-change-access" aria-label="Permalink to &quot;Request or Change Access&quot;">​</a></h2><p>Workspace access is managed by platform administrators in prokube, and by workspace owners when owner self-service is enabled. If you need access to a workspace, contact the workspace owner or platform administrator.</p><p>If you administer prokube, see <a href="./../admin/user_management.html">User Management</a>.</p><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./../labs/">Using Labs</a></li><li><a href="./../admin/user_management.html">User Management</a></li><li><a href="./../admin/network_policies.html">Network Policies</a></li><li><a href="./api_keys.html">API Keys</a></li></ul>',43)])])}const m=a(c,[["render",n]]);export{k as __pageData,m as default};
